**Unit Tests for `run_length_encode`**

```python
import pytest
from typing import List, Tuple


def run_length_encode(s: str) -> list:
    if not s:
        return []
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            result.append((s[i-1], count))
            count = 1
    result.append((s[-1], count))
    return result


# ====================== Happy Path ======================

def test_single_character():
    assert run_length_encode("A") == [("A", 1)]


def test_all_unique_characters():
    assert run_length_encode("abcde") == [("a", 1), ("b", 1), ("c", 1), ("d", 1), ("e", 1)]


def test_all_identical_characters():
    assert run_length_encode("aaaaaaa") == [("a", 7)]


def test_mixed_runs():
    assert run_length_encode("aaabbcdddd") == [("a", 3), ("b", 2), ("c", 1), ("d", 4)]


def test_with_numbers_and_symbols():
    assert run_length_encode("112233aaa!!!") == [("1", 2), ("2", 2), ("3", 2), ("a", 3), ("!", 3)]


def test_long_run():
    s = "a" * 1000
    assert run_length_encode(s) == [("a", 1000)]


# ====================== Edge Cases ======================

def test_empty_string():
    assert run_length_encode("") == []


def test_single_character_repeated_twice():
    assert run_length_encode("aa") == [("a", 2)]


def test_two_different_characters():
    assert run_length_encode("ab") == [("a", 1), ("b", 1)]


def test_alternating_characters():
    assert run_length_encode("abababab") == [("a", 1), ("b", 1)] * 4


def test_unicode_characters():
    assert run_length_encode("hélloééé") == [("h", 1), ("é", 1), ("l", 2), ("o", 1), ("é", 3)]


# ====================== Error Cases ======================

def test_non_string_input_raises_type_error():
    with pytest.raises(TypeError):
        run_length_encode(None)  # type: ignore

    with pytest.raises(TypeError):
        run_length_encode(123)  # type: ignore

    with pytest.raises(TypeError):
        run_length_encode(['a', 'a', 'b'])  # type: ignore


def test_bytes_input_raises_type_error():
    with pytest.raises(TypeError):
        run_length_encode(b"aaaabb")  # type: ignore
```

These tests cover:

- **Happy path**: Normal cases with various patterns
- **Edge cases**: Empty string, single characters, alternating, unicode
- **Error cases**: Type errors for non-string inputs (as expected from type hint and implementation)

The tests are written in standard `pytest` style with clear, descriptive function names.
